mapper.select:
SELECT
  song_id   AS songId,
  COUNT(*)  AS playCount
FROM play_log
WHERE play_time >= #{startTime}
  AND play_time <= #{endTime}
GROUP BY song_id
ORDER BY playCount DESC
LIMIT #{limit}

SELECT pl.id, pl.song_id AS songId, pl.user_id AS userId, pl.play_time AS playTime, s.name AS songName, s.pic AS songPic FROM play_log pl LEFT JOIN song s ON pl.song_id = s.id WHERE 1=1
AND s.name LIKE CONCAT('%', #{songName}, '%')
AND pl.user_id = #{userId}
ORDER BY pl.play_time DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM play_log pl LEFT JOIN song s ON pl.song_id = s.id WHERE 1=1
AND s.name LIKE CONCAT('%', #{songName}, '%')
AND pl.user_id = #{userId}
